import{_ as e,a,b as i,c as n}from"./chunks/acesNark.CWowxZ7N.js";import{c as s,Q as o,j as r,m as l}from"./chunks/framework.D5MFXpji.js";const k=JSON.parse('{"title":"Tone Mapping","description":"","frontmatter":{"title":"Tone Mapping","order":3},"headers":[],"relativePath":"en/post-effect/tone-mapping.md","filePath":"en/post-effect/tone-mapping.md","lastUpdated":1781144716000}'),d={name:"en/post-effect/tone-mapping.md"};function p(g,t,c,h,m,f){return o(),r("div",null,[...t[0]||(t[0]=[l(`<h1 id="tone-mapping" tabindex="-1">Tone Mapping <a class="header-anchor" href="#tone-mapping" aria-label="Permalink to &quot;Tone Mapping&quot;">​</a></h1><p>Tone mapping is an essential post-processing technique that naturally maps the wide brightness range of High Dynamic Range (HDR) images into the limited representation range of standard display devices (LDR). It determines the ultimate visual quality of your rendering by coordinating the scene&#39;s exposure, contrast, and overall color palette.</p><h2 id="_1-operating-principle-smart-tone-mapping-transition" tabindex="-1">1. Operating Principle: Smart Tone Mapping Transition <a class="header-anchor" href="#_1-operating-principle-smart-tone-mapping-transition" aria-label="Permalink to &quot;1. Operating Principle: Smart Tone Mapping Transition&quot;">​</a></h2><p>In RedGPU, tone mapping does not execute at a fixed position like simply at the beginning or the end of the pipeline. Instead, the <code>PostEffectManager</code> dynamically controls the timing internally to facilitate smooth transitions between efficient HDR calculations and LDR post-processing.</p><ul><li><strong>HDR Retention</strong>: Immediately after scene rendering, effects that demand precise depth information and a wide color gamut—such as <code>SkyAtmosphere</code>, <code>SSAO</code>, and <code>SSR</code>—are calculated on the <strong>HDR source data</strong> prior to tone mapping.</li><li><strong>Smart Transition Timing</strong>: The engine iterates through the user general effects loop registered via <code>view.postEffectManager.addEffect()</code>. <strong>As soon as it encounters the first LDR (Low Dynamic Range) effect, it immediately performs tone mapping.</strong></li><li><strong>Default Fallback</strong>: If no LDR effects are registered in the general effect chain, tone mapping is automatically applied at the very last step of the pipeline loop.</li></ul><hr><h2 id="_2-tonemappingmanager-settings" tabindex="-1">2. ToneMappingManager Settings <a class="header-anchor" href="#_2-tonemappingmanager-settings" aria-label="Permalink to &quot;2. ToneMappingManager Settings&quot;">​</a></h2><p>All tone mapping parameters can be dynamically adjusted using the properties of <code>view.toneMappingManager</code>. This manager is built-in upon the creation of a <code>View3D</code> instance, eliminating the need to instantiate it manually.</p><h3 id="_2-1-property-reference" tabindex="-1">2.1 Property Reference <a class="header-anchor" href="#_2-1-property-reference" aria-label="Permalink to &quot;2.1 Property Reference&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Property Name</th><th style="text-align:left;">Default Value</th><th style="text-align:left;">Range</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>mode</code></strong></td><td style="text-align:left;"><code>KHRONOS_PBR_NEUTRAL</code></td><td style="text-align:left;">-</td><td style="text-align:left;">The tone mapping algorithm type (<code>RedGPU.ToneMapping.TONE_MAPPING_MODE</code>).</td></tr><tr><td style="text-align:left;"><strong><code>contrast</code></strong></td><td style="text-align:left;"><code>1.0</code></td><td style="text-align:left;"><code>0.0</code> to <code>2.0</code></td><td style="text-align:left;">Contrast intensity.</td></tr><tr><td style="text-align:left;"><strong><code>brightness</code></strong></td><td style="text-align:left;"><code>0.0</code></td><td style="text-align:left;"><code>-1.0</code> to <code>1.0</code></td><td style="text-align:left;">Additional brightness correction for shadow/highlight areas.</td></tr></tbody></table><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Fine-tune contrast and brightness to emphasize visual impact</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> tm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> view.toneMappingManager;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tm.contrast </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.05</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tm.brightness </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.02</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><hr><h2 id="_3-supported-algorithms-tone-mapping-mode" tabindex="-1">3. Supported Algorithms (TONE_MAPPING_MODE) <a class="header-anchor" href="#_3-supported-algorithms-tone-mapping-mode" aria-label="Permalink to &quot;3. Supported Algorithms (TONE_MAPPING_MODE)&quot;">​</a></h2><p>You can change the tone mapping mode in real-time depending on your target visual style. Constants are declared under the <code>RedGPU.ToneMapping.TONE_MAPPING_MODE</code> namespace.</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Apply ACES Filmic algorithm for a cinematic atmosphere</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">view.toneMappingManager.mode </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> RedGPU.ToneMapping.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">TONE_MAPPING_MODE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ACES_FILMIC_HILL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><table tabindex="0"><thead><tr><th style="text-align:left;">Mode Constant</th><th style="text-align:left;">Description</th><th style="text-align:left;">Comparison Image</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>LINEAR</code></strong></td><td style="text-align:left;">Outputs straight to the device range without any correction. Highlights and shadow details may suffer significant clipping.</td><td style="text-align:left;"><img src="`+e+'" alt="Linear"></td></tr><tr><td style="text-align:left;"><strong><code>KHRONOS_PBR_NEUTRAL</code></strong></td><td style="text-align:left;">Standard algorithm designed to preserve color fidelity for physically-based rendering (PBR) (Default)</td><td style="text-align:left;"><img src="'+a+'" alt="Khronos"></td></tr><tr><td style="text-align:left;"><strong><code>ACES_FILMIC_HILL</code></strong></td><td style="text-align:left;">Hill-approximation version of the ACES algorithm, a cinematic movie industry standard creating high contrast.</td><td style="text-align:left;"><img src="'+i+'" alt="ACES Hill"></td></tr><tr><td style="text-align:left;"><strong><code>ACES_FILMIC_NARKOWICZ</code></strong></td><td style="text-align:left;">Narkowicz-approximation version of the ACES algorithm creating dramatic contrast.</td><td style="text-align:left;"><img src="'+n+'" alt="ACES Nark"></td></tr></tbody></table><hr><h2 id="_4-key-summary" tabindex="-1">4. Key Summary <a class="header-anchor" href="#_4-key-summary" aria-label="Permalink to &quot;4. Key Summary&quot;">​</a></h2><ul><li>Tone mapping settings are supervised by the <code>ToneMappingManager</code>, while execution and transition scheduling are optimized automatically by the <code>PostEffectManager</code>.</li><li>It splits dynamically during the effect chain execution to preserve high-fidelity HDR operations (SSAO, SSR).</li><li><code>KHRONOS_PBR_NEUTRAL</code> is recommended for scenes where physical correctness is paramount, whereas the <code>ACES_FILMIC_</code> suite is ideal for artistic, cinematic rendering.</li></ul><h2 id="_5-next-learning-recommendation" tabindex="-1">5. Next Learning Recommendation <a class="header-anchor" href="#_5-next-learning-recommendation" aria-label="Permalink to &quot;5. Next Learning Recommendation&quot;">​</a></h2><ul><li><strong><a href="./builtin-effects.html">Built-in Effects</a></strong>: Activating SSAO and real-time SSR for physical depth.</li><li><strong><a href="./general-effects.html">General Effects</a></strong>: Adding bloom, blur, and grayscale before or after tone mapping.</li></ul>',21)])])}const E=s(d,[["render",p]]);export{k as __pageData,E as default};
